 1	import * as React from 'react';
 2	import { Tooltip } from '@patternfly/react-core';
 3	import { InProgressIcon } from '@patternfly/react-icons/dist/esm/icons/in-progress-icon';
 4	import { BUILDER_NODE_DECORATOR_RADIUS } from './const';
 5	
 6	import './InstallingNodeDecorator.scss';
 7	import '../styles/common.scss';
 8	
 9	type InstallingNodeDecoratorProps = {
10	  content: string;
11	  x: number;
12	  y: number;
13	};
14	const InstallingNodeDecorator: React.FC<InstallingNodeDecoratorProps> = ({
15	  content,
16	  x,
17	  y,
18	}) => {
19	  const iconRef = React.useRef();
20	  return (
21	    <Tooltip triggerRef={iconRef} content={content}>
22	      <g
23	        ref={iconRef}
24	        className="opp-installing-node-decorator"
25	        transform={`translate(${x}, ${y})`}
26	        onClick={(e) => {
27	          e.stopPropagation();
28	        }}
29	      >
30	        <circle
31	          cx={0}
32	          cy={0}
33	          r={BUILDER_NODE_DECORATOR_RADIUS}
34	          className="opp-installing-node-decorator__circle"
35	        />
36	        <g transform="translate(-5, -7)">
37	          <InProgressIcon className="pipelines-console-plugin__spin" />
38	        </g>
39	      </g>
40	    </Tooltip>
41	  );
42	};
43	
44	export default InstallingNodeDecorator;

